import{_ as e,o as i,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"常用网站","description":"","frontmatter":{},"headers":[],"relativePath":"resources/websites.md","filePath":"resources/websites.md","lastUpdated":null}'),r={name:"resources/websites.md"};function o(s,a,h,n,c,p){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="常用网站" tabindex="-1">常用网站 <a class="header-anchor" href="#常用网站" aria-label="Permalink to &quot;常用网站&quot;">​</a></h1><p>一句话：常用网站主要分为模型下载、官方文档、工作流教程、图片后期和社区讨论几类。</p><h2 id="模型与数据平台" tabindex="-1">模型与数据平台 <a class="header-anchor" href="#模型与数据平台" aria-label="Permalink to &quot;模型与数据平台&quot;">​</a></h2><h3 id="hugging-face" tabindex="-1">Hugging Face <a class="header-anchor" href="#hugging-face" aria-label="Permalink to &quot;Hugging Face&quot;">​</a></h3><p>地址：<a href="https://huggingface.co" target="_blank" rel="noreferrer">https://huggingface.co</a></p><p>用途：</p><ul><li>下载开源模型。</li><li>查看模型卡、许可证和文件结构。</li><li>查找官方或研究机构发布的模型。</li></ul><p>注意：下载前看清许可证、所需文件和推荐工作流。</p><h3 id="civitai" tabindex="-1">Civitai <a class="header-anchor" href="#civitai" aria-label="Permalink to &quot;Civitai&quot;">​</a></h3><p>地址：<a href="https://civitai.com" target="_blank" rel="noreferrer">https://civitai.com</a></p><p>用途：</p><ul><li>查找 checkpoint、LoRA、VAE、工作流和示例图。</li><li>查看示例提示词和推荐参数。</li><li>观察模型社区反馈。</li></ul><p>注意：模型质量、许可证和内容分级差异很大，公开使用前要仔细核对。</p><h2 id="工具与官方文档" tabindex="-1">工具与官方文档 <a class="header-anchor" href="#工具与官方文档" aria-label="Permalink to &quot;工具与官方文档&quot;">​</a></h2><h3 id="comfyui" tabindex="-1">ComfyUI <a class="header-anchor" href="#comfyui" aria-label="Permalink to &quot;ComfyUI&quot;">​</a></h3><p>地址：<a href="https://github.com/comfyanonymous/ComfyUI" target="_blank" rel="noreferrer">https://github.com/comfyanonymous/ComfyUI</a></p><p>用途：</p><ul><li>本地节点式 AI 绘画工具。</li><li>学习工作流和节点数据流。</li><li>运行新模型和复杂图像编辑流程。</li></ul><h3 id="vitepress" tabindex="-1">VitePress <a class="header-anchor" href="#vitepress" aria-label="Permalink to &quot;VitePress&quot;">​</a></h3><p>地址：<a href="https://vitepress.dev" target="_blank" rel="noreferrer">https://vitepress.dev</a></p><p>用途：</p><ul><li>搭建静态文档站。</li><li>编写个人知识库、教程和项目文档。</li></ul><h2 id="模型机构与项目" tabindex="-1">模型机构与项目 <a class="header-anchor" href="#模型机构与项目" aria-label="Permalink to &quot;模型机构与项目&quot;">​</a></h2><h3 id="stability-ai" tabindex="-1">Stability AI <a class="header-anchor" href="#stability-ai" aria-label="Permalink to &quot;Stability AI&quot;">​</a></h3><p>地址：<a href="https://stability.ai" target="_blank" rel="noreferrer">https://stability.ai</a></p><p>用途：了解 Stable Diffusion 相关模型与公告。</p><h3 id="black-forest-labs" tabindex="-1">Black Forest Labs <a class="header-anchor" href="#black-forest-labs" aria-label="Permalink to &quot;Black Forest Labs&quot;">​</a></h3><p>地址：<a href="https://blackforestlabs.ai" target="_blank" rel="noreferrer">https://blackforestlabs.ai</a></p><p>用途：了解 FLUX 系列模型与相关发布。</p><h2 id="中文学习入口" tabindex="-1">中文学习入口 <a class="header-anchor" href="#中文学习入口" aria-label="Permalink to &quot;中文学习入口&quot;">​</a></h2><p>中文教程更新很快，建议关注时注意发布时间和适用版本。</p><p>可以搜索：</p><ul><li>ComfyUI 入门教程。</li><li>Stable Diffusion 基础概念。</li><li>LoRA 训练入门。</li><li>ControlNet 教程。</li><li>AI 绘画模型许可证。</li></ul><p>建议优先选择会明确写出模型版本、节点版本、下载来源和参数设置的教程。</p><h2 id="使用外部资源的原则" tabindex="-1">使用外部资源的原则 <a class="header-anchor" href="#使用外部资源的原则" aria-label="Permalink to &quot;使用外部资源的原则&quot;">​</a></h2><ul><li>优先看官方模型卡和官方文档。</li><li>下载前确认许可证。</li><li>不要把未知来源模型用于公开或商业项目。</li><li>不要把别人的作品、角色或素材当作无风险训练素材。</li><li>记录模型来源，方便以后复查。</li></ul>',36)])])}const f=e(r,[["render",o]]);export{b as __pageData,f as default};
